FORUM_POST_FORMAT = "<h2>{headline}</h2><p>{content}</p>{items}"

def build_forum_post(headline, content, items):
    items_html = "<ul>"
    for item in items:
        items_html += f"<li>{item}</li>"
    items_html += "</ul>"

    return FORUM_POST_FORMAT.format(
        headline=headline,
        content=content,
        items=items_html
